<template>
  <div class="cus-approve">
    <el-card>
      <el-row>
        <el-col :span="3">
          <el-col :span="3">
            <img
              v-if="apply_type === 'dealer'"
              class="cus-approve-img"
              src="@/assets/img/adapay/dealer.png"
              alt=""
            >
            <img
              v-if="apply_type === 'distributor'"
              class="cus-approve-img"
              src="@/assets/img/adapay/store.png"
              alt=""
            >
          </el-col>
        </el-col>
        <el-col :span="20">
          <div class="cus-approve-flex">
            <p class="cus-approve-row">
              {{ apply_type === 'distributor' ? distributor_info.name : dealer_info.username }}
            </p>
            <div class="cus-approve-pfonts cus-margin-40">
              <i class="el-icon-location-outline cus-icon" />
              <span>{{
                apply_type === 'distributor'
                  ? distributor_info.province + distributor_info.city
                  : entry_apply_info.adress || '-'
              }}</span>
            </div>
            <div class="cus-float">
              <!-- <el-button @click="onHandleDrawer(true)" type="text">入戶審批</el-button> -->
            </div>
          </div>
          <p class="cus-approve-pfonts">
            <i class="el-icon-s-custom cus-icon" />
            <span>{{ entry_apply_info ? entry_apply_info.user_name : '-' }}</span>
          </p>
          <p v-if="apply_type === 'distributor'" class="cus-approve-pfonts">
            <i class="el-icon-time cus-icon" />
            <span>{{ distributor_info ? distributor_info.hour : '-' }}</span>
          </p>
          <div class="cus-approve-flex">
            <div class="cus-approve-pfonts">
              <i class="el-icon-phone cus-icon" />
              <span>{{
                (apply_type === 'distributor' ? distributor_info.mobile : dealer_info.mobile) +
                  '（企業電話）' || '-'
              }}</span>
            </div>
            <div v-if="apply_type === 'distributor'" class="cus-approve-pfonts cus-margin-50">
              <i class="el-icon-message cus-icon" />
              <span>{{ entry_info.email ? `${entry_info.email}（企業郵箱）` : '-' }}</span>
            </div>
          </div>
        </el-col>
      </el-row>
      <el-row v-if="apply_type === 'distributor'" style="margin-top: 10px">
        <el-tag
          v-for="item in tagsList"
          :key="item.name"
          :type="item.type"
          size="small"
          class="cus-approve-tags"
        >
          {{ item.name }}
        </el-tag>
      </el-row>
    </el-card>
    <el-card>
      <el-tabs v-model="activeName">
        <el-tab-pane v-if="apply_type === 'distributor'" label="基本訊息" name="first">
          <BaseModal :span="20" :label-list="baseInfo" :info="distributor_info" title="地理位置" />
          <el-card v-if="infoList.is_rel_dealer">
            <div slot="header">其他訊息</div>
            <div class="body">
              <el-row>
                <el-col :span="4" style="text-align: right; padding-right: 10px">
                  關聯經銷商:
                </el-col>
                <el-col :span="20" class="cus-btn">
                  <span>{{ dealer_info.username }}</span>
                </el-col>
              </el-row>
            </div>
          </el-card>
        </el-tab-pane>
        <el-tab-pane v-if="apply_type === 'dealer'" label="開戶訊息" name="first">
          <el-row style="height: 350px" type="flex" justify="center" align="middle">
            <span style="color: #ccc">--暫無開戶訊息--</span>
            <!-- <el-col :span='4' style="text-align:right;padding-right:10px">關聯店鋪：</el-col>
            <el-col :span='20' style="color: #1480e3" class="cus-btn">
              <el-button type='text' @click="handleDialogopen(true)">查看詳情</el-button>
            </el-col> -->
          </el-row>
        </el-tab-pane>
      </el-tabs>
    </el-card>
    <!-- <el-drawer
      :visible.sync="visibleDrawer"
      @close='onHandleDrawer(false)'
      :wrapperClosable='false'
      width='70%'
    >
     <p class="">入戶審批</p> -->
    <!-- <RegisterInfo :list="member_type === 'person' ? personInfo : enterPersonInfo" :info='entry_info' title="證件訊息" />
      <RegisterInfo :list="member_type === 'person' ? accountList : enterAccountList" :info='entry_info' title="結算帳戶訊息" />
      <AccountInfo v-if="status === 'WAIT_APPROVE'" :subTitle='subTitle' :info='infoList' @handleClose='onChange' />
      <RegisterInfo v-if="status !== 'WAIT_APPROVE'" :list='isBool ? enterSplitAccountList : splitAccountList' :info='split_ledger_info' :subTitle='subTitle' title="分帳訊息" />
    </el-drawer>  -->
    <drawer :visible-drawer="visibleDrawer" title="入戶審批" @close="onHandleDrawer">
      <div>
        <RegisterInfo
          :list="member_type === 'person' ? personInfo : enterPersonInfo"
          :info="entry_info"
          title="證件訊息"
        />
        <RegisterInfo
          :list="member_type === 'person' ? accountList : enterAccountList"
          :info="entry_info"
          title="結算帳戶訊息"
        />
        <AccountInfo
          v-if="status === 'WAIT_APPROVE'"
          :sub-title="subTitle"
          :info="infoList"
          @handleClose="onChange"
        />
        <RegisterInfo
          v-if="status !== 'WAIT_APPROVE'"
          :list="isBool ? enterSplitAccountList : splitAccountList"
          :info="split_ledger_info"
          :sub-title="subTitle"
          title="分帳訊息"
        />
      </div>
    </drawer>
    <el-dialog
      title="關聯店鋪"
      :visible.sync="visibleModal"
      width="60%"
      :close-on-click-modal="false"
      @before-close="handleDialogOpen(false)"
    >
      <StoreModal :info="modalData" :data="storeList" @click="getDistributor" />
    </el-dialog>
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import district from '@/common/district.json'
import { getDistributorList } from '@/api/marketing'
import { getOpenApproveDetail } from '@/api/adapay/dealer'
import BaseModal from '@/view/mall/marketing/component/BaseModal'
import RegisterInfo from './component/RegisterInfo'
import AccountInfo from './component/AccountInfo'
import StoreModal from './component/StoreModal'
import drawer from './component/drawer.vue'

export default {
  components: { BaseModal, RegisterInfo, AccountInfo, StoreModal, drawer },
  data() {
    return {
      loading: true,
      regions: district,
      activeName: 'first',
      subTitle: '',
      isBool: false,
      params: {
        page: 1,
        pageSize: 20,
        name: '',
        status: '',
        date: '',
        province: '',
        city: '',
        area: ''
      },
      modalData: {
        total_count: '',
        loading: true
      },
      id: '',
      apply_type: '',
      member_type: '',
      status: '',
      infoList: {},
      visibleDrawer: true,
      visibleModal: false,
      storeList: [],
      distributor_info: {},
      entry_apply_info: {},
      entry_info: {},
      dealer_info: {},
      tagsList: [],
      regions_value: [],
      split_ledger_info: {},
      approveStatusList: [
        { name: '全部', value: '' },
        { name: '待審批', value: '待審批' },
        { name: '已審批', value: '已審批' },
        { name: '通過', value: '通過' },
        { name: '不通過', value: '不通過' }
      ],
      total_count: 0,
      list: [],
      baseInfo: [
        { name: '地理位置', field: 'store_address' },
        { name: '地圖定位', field: 'qqmapimg', type: 'pic' },
        { name: '店鋪經緯度', field: '', filter: this.addressFilter }
      ],
      enterPersonInfo: [
        // 企業證件訊息
        { name: '企業名稱', field: 'name' },
        { name: '企業電話', field: 'telphone' },
        { name: '營業執照號', field: 'social_credit_code' },
        { name: '商戶有效日期', field: 'social_credit_code_expires' },
        { name: '法人姓名', field: 'legal_person' },
        { name: '法人手機號碼', field: 'tel_no' },
        { name: '法人身份證號碼', field: 'legal_cert_id' },
        { name: '法人證件有效期', field: 'legal_cert_id_expires' },
        { name: '所在省市', field: 'area' },
        { name: '企業地址', field: 'address' },
        { name: '經營範圍', field: 'business_scope' },
        { name: '郵箱', field: 'email' },
        { name: '郵編', field: 'zip_code' }
      ],
      enterAccountList: [
        // 企業結算訊息
        { name: '結算銀行卡號', field: 'card_no' },
        { name: '結算銀行卡開戶姓名', field: 'card_name' },
        { name: '結算銀行卡所屬銀行', field: 'bank_name' },
        { name: '結算銀行卡帳戶類型', field: 'bank_acct_type', filter: this.bankFilter }
      ],
      enterSplitAccountList: [
        // 企業分帳訊息
        { name: '手續費扣費方式', field: 'adapay_fee_mode', filter: this.adapayFilter },
        { name: '總部分帳占比', field: 'headquarters_proportion', filter: this.headquartersFilter },
        { name: '審批狀態', field: 'status', filter: this.statusFilter },
        { name: '審批備注', field: 'comments' }
      ],
      splitAccountList: [
        // 企業分帳訊息
        { name: '手續費扣費方式', field: 'adapay_fee_mode', filter: this.adapayFilter },
        { name: '總部分帳占比', field: 'headquarters_proportion', filter: this.headquartersFilter },
        { name: '經銷商分帳占比', field: 'dealer_proportion', filter: this.dealerFilter },
        { name: '審批狀態', field: 'status', filter: this.statusFilter },
        { name: '審批備注', field: 'comments' }
      ],
      personInfo: [
        // 個人證件訊息
        { name: '用戶姓名', field: 'user_name' },
        { name: '用戶手機號碼', field: 'tel_no' },
        { name: '用戶身份證號碼', field: 'cert_id' }
      ],
      accountList: [
        // 個人結算訊息
        { name: '開戶人姓名', field: 'bank_card_name' },
        { name: '銀行預留手機號', field: 'bank_tel_no' },
        { name: '結算銀行卡號', field: 'bank_card_id' },
        { name: '開戶人證件號碼', field: 'bank_cert_id' }
      ]
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  },
  mounted() {
    if (this.$route.query.id) {
      const { id } = this.$route.query || {}
      this.id = id
      this.getDetail(id)
      let params = { page: 1, pageSize: 10, is_valid: 'true' }
      this.getDistributor(params)
    }
  },
  methods: {
    getDetail(id) {
      getOpenApproveDetail(id)
        .then((response) => {
          const { is_rel_dealer, distributor_info, entry_apply_info, entry_info, dealer_info } =
            response.data.data || {}
          this.infoList = response.data.data
          this.status = entry_apply_info.status
          this.apply_type = entry_apply_info.apply_type
          this.member_type = entry_info.member_type || {}
          this.distributor_info = distributor_info || {}
          this.entry_apply_info = entry_apply_info || {}
          this.entry_info = entry_info || {}
          this.dealer_info = dealer_info || {}
          if (entry_apply_info.apply_type === 'distributor') {
            this.split_ledger_info = {
              status: entry_apply_info.status,
              comments: entry_apply_info.comments,
              ...JSON.parse(distributor_info.split_ledger_info)
            }
          } else {
            this.split_ledger_info = {
              status: entry_apply_info.status,
              comments: entry_apply_info.comments,
              ...JSON.parse(dealer_info.split_ledger_info)
            }
          }
          let isBool = entry_apply_info.apply_type === 'distributor' && !is_rel_dealer
          this.subTitle = isBool
            ? `分帳金額計算公式內扣：
            總部：（交易金額-手續費）*總部分帳占比；
            店鋪：訂單金額-手續費-總部分帳金額。
            外扣：
            總部：交易金額*總部分帳占比；
            店鋪：訂單金額-總部分帳金額。`
            : ` 分帳金額計算公式：
            內扣：
            總部：（交易金額-手續費）*總部分帳占比；
            經銷商:（交易金額-手續費）*經銷商分帳占比；
            店鋪：訂單金額-手續費-總部分帳金額-經銷商分帳金額。
            外扣：
            總部：交易金額*總部分帳占比；
            經銷商:交易金額*經銷商分帳占比；
            店鋪：訂單金額-總部分帳金額-經銷商分帳金額。`
          this.isBool = isBool
          const { auto_sync_goods, is_ziti, is_delivery, company_dada_open } =
            distributor_info || {}
          if (auto_sync_goods) {
            this.tagsList.push({ name: '自動上架商品', type: 'danger' })
          }
          if (is_ziti) {
            this.tagsList.push({ name: '支持自取', type: '' })
          }
          if (is_delivery) {
            this.tagsList.push({ name: '支持快遞', type: 'success' })
          }
          if (company_dada_open) {
            this.tagsList.push({ name: '同城配', type: 'warning' })
          }
        })
        .catch((error) => {
          this.loading = false
          this.$message({
            type: 'error',
            message: '獲取門店詳情出錯'
          })
        })
    },
    onChange(type) {
      if (type === 'update') {
        this.getDetail(this.id)
      }
      this.onHandleDrawer(true)
    },
    onHandleDrawer(visible) {
      this.visibleDrawer = visible
      // this.visibleModal = false
    },
    statusFilter() {
      let returnValue = ''
      switch (this.entry_apply_info.status) {
        case 'WAIT_APPROVE':
          returnValue = '待審批'
          break
        case 'APPROVED':
          returnValue = '審核通過'
          break
        case 'REJECT':
          returnValue = '審核失敗'
          break
        default:
          returnValue = '-'
          break
      }
      return returnValue
    },
    addressFilter() {
      const { lat, lng } = this.distributor_info || {}
      if (lat && lng) {
        return lng + ' - ' + lat
      } else {
        return '-'
      }
    },
    headquartersFilter() {
      // 總部分帳占比過濾
      let { headquarters_proportion } = this.split_ledger_info
      let value = this.split_ledger_info.headquarters_proportion
      return value ? value + '%' : '-'
    },
    dealerFilter() {
      // 經銷商分帳占比過濾
      let { dealer_proportion } = this.split_ledger_info
      let value = this.split_ledger_info.dealer_proportion
      return value ? value + '%' : '-'
    },
    adapayFilter() {
      let { adapay_fee_mode } = this.split_ledger_info
      let returnValue = ''
      switch (adapay_fee_mode) {
        case 'I':
          returnValue = '內扣'
          break
        case 'O':
          returnValue = '外扣'
          break
      }
      return returnValue
    },
    bankFilter() {
      let { bank_acct_type } = this.entry_info
      let returnValue = ''
      switch (bank_acct_type) {
        case '1':
          returnValue = '對公'
          break
        case '2':
          returnValue = '對私'
          break
      }
      return returnValue
    },
    handleDialogOpen(visible) {
      // 查看店鋪彈框
      this.visibleModal = visible
    },
    getDistributor(parmas) {
      getDistributorList(parmas).then((response) => {
        this.storeList = response.data.data.list
        this.modalData.total_count = parseInt(response.data.data.total_count)
        this.modalData.loading = false
      })
    }
  }
}
</script>
